SELECT id, order_no, user_id, activity_id, seckill_product_id, sku_id, product_name, seckill_price, quantity, total_amount, status, order_time, pay_time, cancel_time, cancel_reason, create_time, address_id, update_time, alipay_product_code, wechat_product_code FROM ( SELECT id, order_no, user_id, activity_id, seckill_product_id, sku_id, product_name, seckill_price, quantity, total_amount, status, order_time, pay_time, cancel_time, cancel_reason, create_time, address_id, update_time, alipay_product_code, wechat_product_code FROM t_seckill_order_0 WHERE 1=1
AND order_no LIKE CONCAT('%', #{orderNo}, '%')
AND status = #{status}
AND order_time >= #{startDate}
AND order_time <= #{endDate}
UNION ALL SELECT id, order_no, user_id, activity_id, seckill_product_id, sku_id, product_name, seckill_price, quantity, total_amount, status, order_time, pay_time, cancel_time, cancel_reason, create_time, address_id, update_time, alipay_product_code, wechat_product_code FROM t_seckill_order_1 WHERE 1=1
AND order_no LIKE CONCAT('%', #{orderNo}, '%')
AND status = #{status}
AND order_time >= #{startDate}
AND order_time <= #{endDate}
) t ORDER BY create_time DESC LIMIT #{offset}, #{limit}
